import path from 'path';
import { promises as fs } from 'fs';
import { NextResponse } from 'next/server';
import { ProjectInfo, resolveProjectsDir, resolveStateFilePath } from '@/lib/projects';

/**
 * Derives project status from the workspace state file.
 * - 'active'  → state file exists and has in_progress tasks
 * - 'error'   → state file exists, has failed tasks, no in_progress tasks
 * - 'idle'    → state file missing or no in_progress/failed tasks
 */
async function deriveProjectStatus(projectId: string): Promise<'active' | 'idle' | 'error'> {
  const stateFilePath = resolveStateFilePath(projectId);
  try {
    const data = await fs.readFile(stateFilePath, 'utf8');
    const state = JSON.parse(data);
    const tasks: Record<string, { status?: string }> = state.tasks || {};
    const taskList = Object.values(tasks);

    const hasInProgress = taskList.some((t) => t.status === 'in_progress');
    const hasFailed = taskList.some((t) => t.status === 'failed');

    if (hasInProgress) return 'active';
    if (hasFailed) return 'error';
    return 'idle';
  } catch {
    // State file missing or unreadable → idle
    return 'idle';
  }
}

export async function GET() {
  try {
    const projectsDir = resolveProjectsDir();
    const entries = await fs.readdir(projectsDir, { withFileTypes: true });

    const projects: ProjectInfo[] = [];

    for (const entry of entries) {
      if (!entry.isDirectory() || entry.name.startsWith('_')) continue;

      const projectJsonPath = path.join(projectsDir, entry.name, 'project.json');
      try {
        const raw = await fs.readFile(projectJsonPath, 'utf8');
        const parsed = JSON.parse(raw);

        const id: string = parsed.id || entry.name;
        const name: string = parsed.name || id;
        const status = await deriveProjectStatus(id);

        projects.push({ id, name, status });
      } catch {
        // Skip directories without a valid project.json
      }
    }

    // Sort alphabetically by name
    projects.sort((a, b) => a.name.localeCompare(b.name));

    return NextResponse.json({ projects });
  } catch (error) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    console.error('[projects] Error scanning projects directory:', errorMessage);
    return NextResponse.json(
      { error: `Failed to scan projects: ${errorMessage}`, projects: [] },
      { status: 500 }
    );
  }
}
